import React , { useState } from 'react'
import { Link } from 'react-router-dom'
import {ToastContainer} from 'react-toastify'
import { handleError, handleSucsess } from '../utils';

function Signup() {
  const[loginInfo, setLoginForm] = useState({
     name:'',
      email:'',
      password:''
});

const handleChange = (e) => {
  const { name, value } = e.target;
  console.log(name, value);
  const updatedLoginInfo = { ...loginInfo, [name]: value };
  setLoginForm(updatedLoginInfo);
};

console.log('loginInfo ->', loginInfo);
const handleSignup = async(e) => {
 e.preventDefault();
 const {name, email, password} = loginInfo;
 if(!name || !email || !password){
   return handleError('Please fill all the fields');
 }
 try{
  const url = 'http://localhost:8080/auth/signup';
  const response = await fetch(url,{
   method: 'POST',
    headers: {
      'Content-Type': 'application/json',
    },
    body: JSON.stringify(loginInfo),
  });
  const data = await response.json();
  const {success, message }= data
  if(success){
    handleSucsess(message);
  }else{
    handleError(message);
  }

 }catch(error){
   handleError('Something went wrong');
 }

}

  return (
    <div className='container'>
   <h1>Login</h1>
   <form onSubmit={handleSignup}>
     <div>
        <label htmlFor='name'>Name</label>
        
        <input
            onChange={handleChange}
        type="text"
         name='name'
        autoFocus
        placeholder='Enter your Name'
        value={loginInfo.name}
        /></div>

<div>
        <label htmlFor='email'>Email</label>
        <input 
        onChange={handleChange}
        type="email"
         name='email'
        autoFocus
        placeholder='Enter your Email...'
        value={loginInfo.email}
        /></div>


<div>
        <label htmlFor='password'>Password</label>
        <input 
        onChange={handleChange}
        type="password"
         name='password'
        placeholder='Enter your Password..'
        value={loginInfo.password}
        /></div>
        <button type='submit'>Signup</button>
       <span>Already have an account ? 
          <Link to='/login'>Login</Link>
          </span>

    </form> 
    <ToastContainer/>     
    </div>
  )
}

export default Signup
